import{_ as a,a as e,b as d,c as r}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as o,o as i,c as n,a2 as h}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"중복 백업과 읽기 소스 전환","description":"","frontmatter":{},"headers":[],"relativePath":"ko-KR/Other/redundant-backup-and-read-source.md","filePath":"ko-KR/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),l={name:"ko-KR/Other/redundant-backup-and-read-source.md"};function s(p,t,c,b,u,_){return i(),n("div",null,[...t[0]||(t[0]=[h('<h1 id="중복-백업과-읽기-소스-전환" tabindex="-1">중복 백업과 읽기 소스 전환 <a class="header-anchor" href="#중복-백업과-읽기-소스-전환" aria-label="Permalink to &quot;중복 백업과 읽기 소스 전환&quot;">​</a></h1><p>중복 백업은 이미 업로드된 파일을 다른 저장 채널에도 한 벌 더 저장하는 기능입니다.</p><p>사용자가 파일을 볼 때는 원본과 백업의 차이가 거의 없습니다. 실제로 어느 저장 채널에서 읽어 오느냐만 달라집니다.</p><h2 id="할-수-있는-일" tabindex="-1">할 수 있는 일 <a class="header-anchor" href="#할-수-있는-일" aria-label="Permalink to &quot;할 수 있는 일&quot;">​</a></h2><table tabindex="0"><thead><tr><th>기능</th><th>설명</th></tr></thead><tbody><tr><td>파일을 한 번 더 저장</td><td>다른 업로드 채널에 사본을 만들어 단일 저장소 장애 위험을 줄입니다</td></tr><tr><td>읽기 소스 전환</td><td>백업 후 원본 채널과 백업 채널 사이에서 읽기 위치를 바꿀 수 있습니다</td></tr><tr><td>단일 파일 백업</td><td>파일 상세 화면에서 중요한 파일 하나만 백업합니다</td></tr><tr><td>일괄 백업</td><td>관리자 화면에서 여러 파일을 선택해 한 번에 백업합니다</td></tr><tr><td>전체 보강 백업</td><td>기타 설정에서 폴더 단위로 빠진 백업을 채웁니다</td></tr></tbody></table><h2 id="설정-위치" tabindex="-1">설정 위치 <a class="header-anchor" href="#설정-위치" aria-label="Permalink to &quot;설정 위치&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>시스템 설정 -&gt; 기타 설정 -&gt; 중복 백업</span></span></code></pre></div><p><img src="'+a+'" alt="중복 백업" loading="lazy"></p><p>이곳에서는 특정 폴더 또는 전체 파일에 대해 백업을 추가할 수 있습니다. 백업 채널은 직접 선택할 수도 있고, 자동 전환을 선택해 시스템이 적절한 채널을 고르게 할 수도 있습니다.</p><h2 id="파일-상세에서-백업하기" tabindex="-1">파일 상세에서 백업하기 <a class="header-anchor" href="#파일-상세에서-백업하기" aria-label="Permalink to &quot;파일 상세에서 백업하기&quot;">​</a></h2><p>관리 화면에서 파일 상세를 열면 해당 파일만 바로 백업할 수 있습니다.</p><p><img src="'+e+'" alt="파일 상세 백업" loading="lazy"></p><p>중요한 파일을 나중에 따로 보호하고 싶을 때 적합합니다. 백업이 성공하면 파일 상세에 읽기 소스 전환 항목이 표시됩니다.</p><h2 id="여러-파일-일괄-백업" tabindex="-1">여러 파일 일괄 백업 <a class="header-anchor" href="#여러-파일-일괄-백업" aria-label="Permalink to &quot;여러 파일 일괄 백업&quot;">​</a></h2><p>관리 화면에서 여러 파일을 선택한 뒤 일괄 백업을 실행할 수 있습니다.</p><p><img src="'+d+'" alt="일괄 백업" loading="lazy"></p><p>파일 상세 백업, 선택 백업, 기타 설정의 중복 백업은 모두 같은 백업 기능을 다른 입구에서 실행하는 방식입니다.</p><h2 id="백업-후-읽기-소스-전환" tabindex="-1">백업 후 읽기 소스 전환 <a class="header-anchor" href="#백업-후-읽기-소스-전환" aria-label="Permalink to &quot;백업 후 읽기 소스 전환&quot;">​</a></h2><table tabindex="0"><thead><tr><th>읽기 소스</th><th>설명</th></tr></thead><tbody><tr><td>원본 채널</td><td>처음 업로드한 저장 채널에서 읽습니다</td></tr><tr><td>백업 채널</td><td>중복 백업으로 만든 사본 채널에서 읽습니다</td></tr></tbody></table><p><img src="'+r+'" alt="읽기 소스 전환" loading="lazy"></p><p>어느 쪽으로 전환하든 이미지 표시, 동영상 재생, 다운로드 링크는 평소처럼 사용할 수 있습니다.</p><h2 id="건너뛰는-경우" tabindex="-1">건너뛰는 경우 <a class="header-anchor" href="#건너뛰는-경우" aria-label="Permalink to &quot;건너뛰는 경우&quot;">​</a></h2><table tabindex="0"><thead><tr><th>경우</th><th>이유</th></tr></thead><tbody><tr><td>이미 백업됨</td><td>중복 저장으로 공간을 낭비하지 않기 위해</td></tr><tr><td>원본과 백업 채널이 같음</td><td>같은 저장소에 다시 저장하면 백업 의미가 없기 때문에</td></tr><tr><td>사용 가능한 백업 채널 없음</td><td>다른 적절한 저장 채널을 찾지 못했기 때문에</td></tr></tbody></table><h2 id="삭제할-때" tabindex="-1">삭제할 때 <a class="header-anchor" href="#삭제할-때" aria-label="Permalink to &quot;삭제할 때&quot;">​</a></h2><p>파일을 삭제하면 원본 파일과 백업 파일이 함께 삭제됩니다.</p>',25)])])}const g=o(l,[["render",s]]);export{f as __pageData,g as default};
